let data = null;
try { data = JSON.parse(stripped); } catch (e) {
  const m = stripped.match(/\{[\s\S]*\}/);
  if (m) { try { data = JSON.parse(m[0]); } catch (e2) {} }
}
function arr(v) {
  if (Array.isArray(v)) return v.slice(0, 8).map(String);
  if (typeof v === 'string' && v.includes(',')) return v.split(',').map(s => s.trim()).filter(Boolean).slice(0, 8);
  if (v == null || v === '') return [];
  return [String(v)];
}
if (!data || typeof data !== 'object') {
  return [{ json: { output: null, extract_error: true, raw_preview: String(raw).slice(0, 500) } }];
}
const rd = ['escalation','reviewer_queue','auto_file'].includes(data.routing_decision) ? data.routing_decision : 'reviewer_queue';
return [{ json: { output: {
  contract_type: data.contract_type ?? 'other',
  parties: arr(data.parties),
  jurisdiction: data.jurisdiction ?? 'unknown',
  sensitive_topics: arr(data.sensitive_topics),
  key_concerns: arr(data.key_concerns).slice(0, 5),
