} } }];

const item = $input.first().json;
const raw = typeof item.text === 'string' ? item.text : typeof item.output === 'string' ? item.output : '';
let stripped = String(raw).replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
let data = null;
try { data = JSON.parse(stripped); } catch (e) {
  const m = stripped.match(/\{[\s\S]*\}/);
  if (m) { try { data = JSON.parse(m[0]); } catch (e2) {} }
}
if (data && data.report && typeof data.report === 'object') data = data.report;
const fallback = {
  contract_type: 'unknown',
  routing_decision: 'reviewer_queue',
  jurisdiction: 'unknown',
  parties: [],
  overall_risk: 'Medium',
  findings: [],
  similar_regulations: [],
  rag_insight: '',
  enrichment_notes: 'Could not parse final report JSON.',
  confidence: 0,
  parse_error: true
};
if (!data || typeof data !== 'object') {
  return [{ json: { ...fallback, raw_preview: String(raw).slice(0, 800) } }];
}
const risk = data.overall_risk || 'Medium';
if (!data.routing_decision) {
  data.routing_decision = risk === 'High' ? 'escalation' : risk === 'Low' ? 'auto_file' : 'reviewer_queue';
}
return [{ json: data }];
